import React, { useState } from 'react';
import { User, Camera, Check } from 'lucide-react';

interface ProfileCardProps {
  onSave: (data: { name: string; bio: string; avatar: File | null }) => void;
}

const ProfileCard: React.FC<ProfileCardProps> = ({ onSave }) => {
  const [name, setName] = useState<string>('');
  const [bio, setBio] = useState<string>('');
  const [avatar, setAvatar] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string>('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSuccessMessage('');

    if (!name) {
      setError('Name is required.');
      return;
    }

    setIsSubmitting(true);
    onSave({ name, bio, avatar });
    setSuccessMessage('Profile saved successfully!');
    setIsSubmitting(false);
  };

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      setAvatar(e.target.files[0]);
    }
  };

  return (
    <div className="flex justify-center items-center min-h-screen bg-gray-100">
      <form
        onSubmit={handleSubmit}
        aria-label="Profile Settings Form"
        className="bg-white shadow-lg rounded-lg p-6 max-w-md w-full"
      >
        <fieldset className="mb-4">
          <legend className="text-xl font-semibold text-gray-800">Profile Information</legend>
          <div className="mb-4">
            <label htmlFor="name-input" className="block text-gray-700 font-medium mb-2">
              Name
            </label>
            <input
              id="name-input"
              type="text"
              placeholder="Enter your name"
              required
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 transition duration-150"
              aria-describedby={error ? 'name-error' : undefined}
              aria-required="true"
            />
            {error && <p id="name-error" className="text-red-500 text-sm">{error}</p>}
          </div>

          <div className="mb-4">
            <label htmlFor="bio-textarea" className="block text-gray-700 font-medium mb-2">
              Bio
            </label>
            <textarea
              id="bio-textarea"
              placeholder="Tell us about yourself"
              value={bio}
              onChange={(e) => setBio(e.target.value)}
              className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 transition duration-150"
              rows={4}
            />
          </div>

          <div className="mb-4">
            <label htmlFor="avatar-upload" className="block text-gray-700 font-medium mb-2 flex items-center">
              <Camera className="mr-2" />
              Avatar
            </label>
            <input
              id="avatar-upload"
              type="file"
              accept="image/*"
              onChange={handleAvatarChange}
              className="border border-gray-300 rounded-lg p-2 w-full cursor-pointer focus:ring-2 focus:ring-blue-500 transition duration-150"
            />
            {avatar && <p className="text-gray-600 mt-2">Selected file: {avatar.name}</p>}
          </div>
        </fieldset>

        <button
          type="submit"
          disabled={isSubmitting}
          className={`flex items-center justify-center w-full py-2 px-4 rounded-lg text-white transition duration-300 ${
            isSubmitting ? 'bg-gray-400 cursor-not-allowed' : 'bg-blue-500 hover:bg-blue-600'
          }`}
          aria-label="Save Profile"
        >
          {isSubmitting ? 'Saving...' : <><Check className="mr-2" /> Save</>}
        </button>

        {successMessage && (
          <div role="alert" aria-live="polite" className="mt-4 text-green-600">
            {successMessage}
          </div>
        )}
      </form>
    </div>
  );
};

export default ProfileCard;

import React, { useState } from 'react';
import { Lock, User } from 'lucide-react';

interface Props {
  onSubmit: (email: string, password: string) => Promise<void>;
}

const LoginPage: React.FC<Props> = ({ onSubmit }) => {
  const [email, setEmail] = useState<string>('');
  const [password, setPassword] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string>('');

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    setError('');

    if (!email || !password) {
      setError('Both fields are required.');
      return;
    }

    if (!/\S+@\S+\.\S+/.test(email)) {
      setError('Please enter a valid email address.');
      return;
    }

    setLoading(true);
    try {
      await onSubmit(email, password);
    } catch (err) {
      setError('Login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex items-center justify-center min-h-screen bg-gray-100">
      <form 
        onSubmit={handleSubmit} 
        aria-label="Login Form" 
        className="bg-white backdrop-blur-lg rounded-xl shadow-lg p-8 max-w-md w-full"
      >
        <fieldset className="mb-4">
          <legend className="text-2xl font-bold text-gray-800">Login</legend>

          <div className="mb-4">
            <label htmlFor="email-input" className="block text-gray-700 mb-1">
              <User className="inline mr-2" />
              Email
            </label>
            <input 
              id="email-input" 
              type="email" 
              placeholder="Enter your email" 
              required 
              value={email} 
              onChange={(e) => setEmail(e.target.value)} 
              className="w-full p-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              aria-describedby={error ? "email-error" : undefined}
            />
            {error && <span id="email-error" className="text-red-600 text-sm">{error}</span>}
          </div>

          <div className="mb-4">
            <label htmlFor="password-input" className="block text-gray-700 mb-1">
              <Lock className="inline mr-2" />
              Password
            </label>
            <input 
              id="password-input" 
              type="password" 
              placeholder="Enter your password" 
              required 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              className="w-full p-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              aria-describedby={error ? "password-error" : undefined}
            />
            {error && <span id="password-error" className="text-red-600 text-sm">{error}</span>}
          </div>

          <button 
            type="submit" 
            disabled={loading} 
            className={`w-full p-2 rounded-lg text-white ${loading ? 'bg-gray-400' : 'bg-blue-600 hover:bg-blue-700 transition-all duration-300 active:scale-95'}`}
            aria-live="polite"
          >
            {loading ? 'Loading...' : 'Login'}
          </button>
        </fieldset>
      </form>
    </div>
  );
};

export default LoginPage;

